## Coordinate Field

A field that captures a 2D coordinate (x, y)

### Usage

```ts
import { CardDef, field, contains } from 'https://cardstack.com/base/card-api';
import CoordinateField from 'https://cardstack.com/base/coordinate';

export class Example extends CardDef {
  @field point = contains(CoordinateField);
}
```
